function curve(day = "today") {
  const seed = day === "tomorrow" ? 23 : 11;
  const out = [];
  for (let i = 0; i < 96; i++) {
    const h = i / 4;
    const morning = 420 * Math.exp(-Math.pow(h - 8, 2) / 8);
    const evening = 580 * Math.exp(-Math.pow(h - 19, 2) / 7);
    const solarDip = -130 * Math.exp(-Math.pow(h - 13, 2) / 10);
    const noise = Math.sin(i * 1.71 + seed) * 42 + Math.cos(i * .37 + seed) * 18;
    const price = Math.max(80, Math.round(410 + morning + evening + solarDip + noise));
    out.push({ interval: i + 1, i, hour: h, label: String(Math.floor(h)).padStart(2, "0") + ":" + String((i % 4) * 15).padStart(2, "0"), price, priceLeiMwh: price, source: "SERVIO fallback OPCOM-like" });
  }
  return out;
}

