  for (const m of matches) {
    const idx = Number(m[1]);
    const price = normalizeRoNumber(m[2]);
    if (idx >= 1 && idx <= 96 && Number.isFinite(price) && !map.has(idx)) map.set(idx, price);
  }
  if (map.size < 90) throw new Error("OPCOM parser returned " + map.size + " intervals, expected ~96");
