          timezone: "Europe/Bucharest",
          entsoePeriodStartUtc: c.periodStart,
          entsoePeriodEndUtc: c.periodEnd,
          entsoePeriodMode: c.key,
          entsoeXmlPeriodStartUtc: parsed.entsoeXmlPeriodStartUtc,
          entsoeXmlPeriodEndUtc: parsed.entsoeXmlPeriodEndUtc,
          entsoeXmlResolution: parsed.entsoeXmlResolution,
          entsoeRawIntervals: normalized.rawIntervals,
          entsoeNormalizedIntervals: normalized.eurPrices.length,
          entsoeInsertedBefore: normalized.insertedBefore,
          entsoeInsertedAfter: normalized.insertedAfter,
          entsoeFilledInternal: normalized.filledInternal,
